1	{
2	  "dependencies": {
3	    "playwright": "^1.60.0"
4	  }
5	}
6

1	const XLSX = require('xlsx');
2	const path = require('path');
3	const fs = require('fs');
4	
5	const DESKTOP = 'C:\\Users\\Administrator\\Desktop';
6	const OUTPUT_FILE = path.join(DESKTOP, '进销项对比分析结果.xlsx');
7	
8	// ====== 1. READ ALL FILES ======
9	console.log('正在读取文件...');
10	
11	const wbJin = XLSX.readFile(path.join(DESKTOP, '壹仕通25年进项.xlsx'));
12	const wbXiao = XLSX.readFile(path.join(DESKTOP, '壹仕通25年销项.xlsx'));
13	const wbRef = XLSX.readFile(path.join(DESKTOP, '过滤条件及关键词库.xlsx'));
14	
15	function readSheetData(wb, sheetName) {
16	    const ws = wb.Sheets[sheetName];
17	    if (!ws) return [];
18	    return XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
19	}
20	
21	const jinRows = readSheetData(wbJin, '信息汇总表');
22	const xiaoRows = readSheetData(wbXiao, '信息汇总表');
23	const filterRows = readSheetData(wbRef, '过滤条件');
24	const keywordRows = readSheetData(wbRef, '关键词库');
25	const unitRows = readSheetData(wbRef, '单位换算');
26	
27	// ====== 2. BUILD REFERENCE DATA ======
28	
29	// 过滤条件列表
30	const filterList = filterRows.slice(1).map(r => r[0]).filter(Boolean).map(v => v.toString().trim());
31	
32	// 关键词库：存为Set (Column B = 标准关键词)
33	const keywordSet = new Set();
34	for (let i = 1; i < keywordRows.length; i++) {
35	    const kw = keywordRows[i][1];
36	    if (kw) keywordSet.add(kw.toString().trim());
37	}
38	
39	// 关键词库：A列→B列映射 (for matching)
40	const keywordMap = new Map();
41	for (let i = 1; i < keywordRows.length; i++) {
42	    const colA = keywordRows[i][0];
43	    const colB = keywordRows[i][1];
44	    if (colA && colB) keywordMap.set(colA.toString().trim(), colB.toString().trim());
45	}
46	
47	// 单位换算表：(product, fromUnit) → {toUnit, rate}
48	const unitMap = new Map();
49	for (let i = 1; i < unitRows.length; i++) {
50	    const r = unitRows[i];
51	    const prod = r[0] ? r[0].toString().trim() : '';
52	    const fromUnit = r[1] ? r[1].toString().trim() : '';
53	    const toUnit = r[2] ? r[2].toString().trim() : '';
54	    const rate = parseFloat(r[3]) || 1;
55	    if (prod && fromUnit && toUnit) {
56	        const key = prod + '||' + fromUnit;
57	        unitMap.set(key, { toUnit, rate });
58	    }
59	}
60	
61	// ====== 3. HELPER FUNCTIONS ======
62	
63	// 提取品类名：取最后一个*后面的内容
64	function extractCategory(name) {
65	    if (!name) return '';
66	    const s = name.toString().trim();
67	    if (!s) return '';
68	    const parts = s.split('*');
69	    return parts[parts.length - 1].trim();
70	}
71	
72	// 判断是否应该被过滤掉
73	function shouldFilter(name, cat) {
74	    if (!name && !cat) return true;
75	    const check = [name.toString(), cat].filter(Boolean);
76	    return check.some(c => filterList.some(f => c.includes(f)));
77	}
78	
79	// 标准关键词匹配：对提取的品类名，尝试找关键词库标准词
80	function getStandardKeyword(category) {
81	    if (!category) return category;
82	    // 1. 精确匹配关键词库B列
83	    if (keywordSet.has(category)) return category;
84	    // 2. 如果品类本身就是某个关键词的一部分，且该关键词在B列中
85	    // 例如 "彩色回形针" → 检查关键词库中是否有 "彩色回形针"
86	    // 这已经被上一步覆盖了
87	
88	    return category; // 没找到就返回原名称
89	}
90	
91	// Bigram Dice相似度
92	function similarity(a, b) {
93	    if (!a || !b) return 0;
94	    if (a === b) return 1;
95	    const s1 = a.toLowerCase();
96	    const s2 = b.toLowerCase();
97	    const bigrams1 = new Set();
98	    const bigrams2 = new Set();
99	    for (let i = 0; i < s1.length - 1; i++) bigrams1.add(s1.substring(i, i + 2));
100	    for (let i = 0; i < s2.length - 1; i++) bigrams2.add(s2.substring(i, i + 2));
101	    if (bigrams1.size === 0 || bigrams2.size === 0) return 0;
102	    let intersection = 0;
103	    for (const b of bigrams1) if (bigrams2.has(b)) intersection++;
104	    return 2 * intersection / (bigrams1.size + bigrams2.size);
105	}
106	
107	// 匹配规则：判断两个品类名是否指向同一类产品
108	function namesMatch(name1, name2) {
109	    if (!name1 || !name2) return null;
110	    const n1 = name1.toString().trim();
111	    const n2 = name2.toString().trim();
112	    if (!n1 || !n2) return null;
113	
114	    // 1. 精确匹配
115	    if (n1 === n2) return '精确匹配';
116	
117	    // 2. 从属匹配：以后缀为准，如"彩色回形针"以"回形针"结尾 → 匹配
118	    // 较短的词必须在关键词库中，且长度>=2（避免"笔"等单字误匹配）
119	    function isSuffixMatch(longer, shorter) {
120	        if (!longer.endsWith(shorter)) return false;
121	        if (!keywordSet.has(shorter) || shorter.length < 2) return false;
122	        // 特殊规则："笔记本"有歧义（文具笔记本 vs 笔记本电脑）
123	        // 如果品类名含英文字母（如"MacBookPro笔记本"），不是文具类笔记本
124	        if (shorter === '笔记本') {
125	            const prefix = longer.slice(0, longer.length - shorter.length);
126	            if (/[a-zA-Z]/.test(prefix)) return false;
127	        }
128	        return true;
129	    }
130	    if (n1.length > n2.length && isSuffixMatch(n1, n2)) return '从属匹配';
131	    if (n2.length > n1.length && isSuffixMatch(n2, n1)) return '从属匹配';
132	
133	    // 3. 85%相似度匹配
134	    const sim = similarity(n1, n2);
135	    if (sim >= 0.85) return '相似度匹配';
136	
137	    return null;
138	}
139	
140	// 单位换算：对一行数据，尝试换算为标准单位
141	function convertUnit(category, spec, origUnit, qty) {
142	    if (!origUnit || !qty) return { unit: origUnit, qty: qty, converted: false };
143	
144	    const u = origUnit.toString().trim();
145	    if (!u) return { unit: origUnit, qty: qty, converted: false };
146	
147	    // 尝试多种方式匹配单位换算表
148	    // 方式1: (品类名, 原单位) 精确匹配
149	    let key = category + '||' + u;
150	    if (unitMap.has(key)) {
151	        const rule = unitMap.get(key);
152	        return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
153	    }
154	
155	    // 方式2: (规格型号中的产品名, 原单位) 匹配
156	    if (spec) {
157	        // 尝试用规格型号中的关键词匹配单位换算表的产品名
158	        for (const [mapKey, rule] of unitMap) {
159	            const [prod, unit] = mapKey.split('||');
160	            if (unit === u && spec.toString().includes(prod)) {
161	                return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
162	            }
163	        }
164	    }
165	
166	    // 方式3: 品类名是换算表产品名的子串
167	    for (const [mapKey, rule] of unitMap) {
168	        const [prod, unit] = mapKey.split('||');
169	        if (unit === u && prod.includes(category)) {
170	            return { unit: rule.toUnit, qty: qty * rule.rate, converted: true, rate: rule.rate };
171	        }
172	    }
173	
174	    return { unit: origUnit, qty: qty, converted: false };
175	}
176	
177	// ====== 4. EXTRACT AND PARSE ALL DATA ======
178	
179	// 列索引：L=11, M=12, N=13, O=14, P=15
180	const COL = { name: 11, spec: 12, unit: 13, qty: 14, price: 15, invoiceNo: 3, date: 8, buyer: 7, seller: 5, note: 26 };
181	
182	function parseRows(rows, source) {
183	    const result = [];
184	    for (let i = 1; i < rows.length; i++) {
185	        const row = rows[i];
186	        const rawName = row[COL.name] ? row[COL.name].toString().trim() : '';
187	        if (!rawName) continue;
188	
189	        const category = extractCategory(rawName);
190	        if (!category || shouldFilter(rawName, category)) continue;
191	
192	        const spec = row[COL.spec] ? row[COL.spec].toString().trim() : '';
193	        const origUnit = row[COL.unit] ? row[COL.unit].toString().trim() : '';
194	        const rawQty = parseFloat(row[COL.qty]) || 0;
195	        const rawPrice = parseFloat(row[COL.price]) || 0;
196	        const invoiceNo = row[COL.invoiceNo] ? row[COL.invoiceNo].toString().trim() : '';
197	        const date = row[COL.date] ? row[COL.date].toString().trim() : '';
198	        const note = row[COL.note] ? row[COL.note].toString().trim() : '';
199	
200	        // 单位换算
201	        const conv = convertUnit(category, spec, origUnit, rawQty);
202	
203	        // 找标准关键词
204	        const keyword = getStandardKeyword(category);
205	
206	        result.push({
207	            rowNum: i,
208	            source,
209	            rawName,
210	            category,
211	            keyword,
212	            spec,
213	            origUnit,
214	            unit: conv.unit,
215	            origQty: rawQty,
216	            qty: conv.qty,
217	            price: rawPrice,
218	            convRate: conv.rate || 1,
219	            converted: conv.converted,
220	            invoiceNo,
221	            date,
222	            note
223	        });
224	    }
225	    return result;
226	}
227	
228	console.log('正在解析数据...');
229	const jinData = parseRows(jinRows, '进项');
230	const xiaoData = parseRows(xiaoRows, '销项');
231	console.log(`进项有效行数: ${jinData.length}, 销项有效行数: ${xiaoData.length}`);
232	
233	// ====== 5. PRODUCT GROUPING ======
234	
235	// 获取所有唯一品类名
236	function getUniqueCategories(data) {
237	    return [...new Set(data.map(d => d.category))];
238	}
239	
240	const jinCats = getUniqueCategories(jinData);
241	const xiaoCats = getUniqueCategories(xiaoData);
242	
243	console.log(`进项品类数: ${jinCats.length}, 销项品类数: ${xiaoCats.length}`);
244	
245	// 构建匹配关系：品类名→产品组ID
246	// 使用并查集(Union-Find)进行分组
247	class UnionFind {
248	    constructor() {
249	        this.parent = new Map();
250	    }
251	    find(x) {
252	        if (!this.parent.has(x)) this.parent.set(x, x);
253	        if (this.parent.get(x) !== x) {
254	            this.parent.set(x, this.find(this.parent.get(x)));
255	        }
256	        return this.parent.get(x);
257	    }
258	    union(x, y) {
259	        const px = this.find(x);
260	        const py = this.find(y);
261	        if (px !== py) this.parent.set(px, py);
262	    }
263	}
264	
265	const uf = new UnionFind();
266	
267	// 先注册所有品类名
268	[...jinCats, ...xiaoCats].forEach(c => uf.find(c));
269	
270	// 匹对进项和销项的品类名
271	let exactCount = 0, containCount = 0, simCount = 0;
272	for (const jCat of jinCats) {
273	    for (const xCat of xiaoCats) {
274	        const matchType = namesMatch(jCat, xCat);
275	        if (matchType) {
276	            uf.union(jCat, xCat);
277	            if (matchType === '精确匹配') exactCount++;
278	            else if (matchType === '从属匹配') containCount++;
279	            else simCount++;
280	        }
281	    }
282	}
283	
284	console.log(`匹配结果: 精确匹配=${exactCount}, 从属匹配=${containCount}, 相似度匹配=${simCount}`);
285	
286	// 构建产品组
287	const groupMap = new Map(); // root → groupId
288	const groups = []; // { id, jinNames: Set, xiaoNames: Set }
289	
290	for (const c of [...new Set([...jinCats, ...xiaoCats])]) {
291	    const root = uf.find(c);
292	    if (!groupMap.has(root)) {
293	        const groupId = groups.length + 1;
294	        groupMap.set(root, groupId);
295	        groups.push({ id: groupId, jinNames: new Set(), xiaoNames: new Set() });
296	    }
297	    const g = groups[groupMap.get(root) - 1];
298	    if (jinCats.includes(c)) g.jinNames.add(c);
299	    if (xiaoCats.includes(c)) g.xiaoNames.add(c);
300	}
301	
302	// 为每个品类名分配组ID
303	const catToGroup = new Map();
304	for (const [root, gid] of groupMap) {
305	    for (const c of [...new Set([...jinCats, ...xiaoCats])]) {
306	        if (uf.find(c) === root) catToGroup.set(c, gid);
307	    }
308	}
309	
310	console.log(`产品组数: ${groups.length}`);
311	
312	// 标记未匹配的品类
313	const matchedJin = new Set();
314	const matchedXiao = new Set();
315	for (const g of groups) {
316	    for (const jn of g.jinNames) matchedJin.add(jn);
317	    for (const xn of g.xiaoNames) matchedXiao.add(xn);
318	}
319	const unmatchedJin = jinCats.filter(c => !matchedJin.has(c));
320	const unmatchedXiao = xiaoCats.filter(c => !matchedXiao.has(c));
321	
322	// 将未匹配的产品各自单独成组
323	for (const c of unmatchedJin) {
324	    const gid = groups.length + 1;
325	    catToGroup.set(c, gid);
326	    groups.push({ id: gid, jinNames: new Set([c]), xiaoNames: new Set() });
327	}
328	for (const c of unmatchedXiao) {
329	    const gid = groups.length + 1;
330	    catToGroup.set(c, gid);
331	    groups.push({ id: gid, jinNames: new Set(), xiaoNames: new Set([c]) });
332	}
333	
334	// 为每行数据分配组ID
335	for (const d of jinData) d.groupId = catToGroup.get(d.category) || 0;
336	for (const d of xiaoData) d.groupId = catToGroup.get(d.category) || 0;
337	
338	// ====== 6. BUILD COMPARISON DATA ======
339	
340	// --- Sheet 1: 数量汇总对比 ---
341	// 每个产品组+单位对比数量
342	function buildQtyComparison(groups, jinData, xiaoData) {
343	    const rows = [];
344	
345	    for (const g of groups) {
346	        // 用进项+销项所有出现过的单位
347	        const jinUnits = new Map(); // unit → totalQty
348	        const xiaoUnits = new Map(); // unit → totalQty
349	
350	        const gJinData = jinData.filter(d => d.groupId === g.id);
351	        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);
352	
353	        for (const d of gJinData) {
354	            jinUnits.set(d.unit, (jinUnits.get(d.unit) || 0) + d.qty);
355	        }
356	        for (const d of gXiaoData) {
357	            xiaoUnits.set(d.unit, (xiaoUnits.get(d.unit) || 0) + d.qty);
358	        }
359	
360	        // 进项名称和销项名称展示
361	        const jinNames = [...g.jinNames].join('; ');
362	        const xiaoNames = [...g.xiaoNames].join('; ');
363	
364	        // 所有涉及的单位
365	        const allUnits = new Set([...jinUnits.keys(), ...xiaoUnits.keys()]);
366	
367	        for (const unit of allUnits) {
368	            const jinQty = jinUnits.get(unit) || 0;
369	            const xiaoQty = xiaoUnits.get(unit) || 0;
370	            const diff = jinQty - xiaoQty;
371	            rows.push({
372	                产品组编号: g.id,
373	                进项品类: jinNames || '—',
374	                销项品类: xiaoNames || '—',
375	                单位: unit,
376	                进项总数量: Math.round(jinQty * 100) / 100,
377	                销项总数量: Math.round(xiaoQty * 100) / 100,
378	                数量差异: Math.round(diff * 100) / 100,
379	                说明: jinQty > 0 && xiaoQty > 0 ? '' : (jinQty > 0 ? '仅有进项' : '仅有销项')
380	            });
381	        }
382	    }
383	    return rows;
384	}
385	
386	// --- Sheet 2: 单价异常明细 ---
387	// 进项单价 > 销项单价的异常行
388	function buildPriceAnomalies(groups, jinData, xiaoData) {
389	    const rows = [];
390	
391	    for (const g of groups) {
392	        const gJinData = jinData.filter(d => d.groupId === g.id);
393	        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);
394	
395	        if (gJinData.length === 0 || gXiaoData.length === 0) continue;
396	
397	        // 收集销项所有去重单价
398	        const xiaoPrices = [...new Set(gXiaoData.map(d => d.price))].sort((a, b) => a - b);
399	        // 收集进项所有去重单价
400	        const jinPrices = [...new Set(gJinData.map(d => d.price))].sort((a, b) => a - b);
401	
402	        if (xiaoPrices.length === 0 || jinPrices.length === 0) continue;
403	
404	        const xiaoMin = xiaoPrices[0];
405	        const jinMax = jinPrices[jinPrices.length - 1];
406	
407	        // 检查：进项最大单价 > 销项最小单价
408	        if (jinMax > xiaoMin) {
409	            // 标记进项中单价 > 销项最小单价的那些行
410	            for (const d of gJinData) {
411	                if (d.price > xiaoMin) {
412	                    rows.push({
413	                        来源: '进项',
414	                        产品组: g.id,
415	                        进项品类: d.category,
416	                        销项品类: [...g.xiaoNames].join('; '),
417	                        发票号码: d.invoiceNo,
418	                        开票日期: d.date,
419	                        单位: d.unit,
420	                        数量: d.qty,
421	                        单价: d.price,
422	                        销项最低单价: xiaoMin,
423	                        差异: Math.round((d.price - xiaoMin) * 100) / 100,
424	                        异常说明: `进项单价${d.price} > 销项最低单价${xiaoMin}`
425	                    });
426	                }
427	            }
428	
429	            // 标记销项中单价 < 进项最大单价的行
430	            for (const d of gXiaoData) {
431	                if (d.price < jinMax) {
432	                    rows.push({
433	                        来源: '销项',
434	                        产品组: g.id,
435	                        进项品类: [...g.jinNames].join('; '),
436	                        销项品类: d.category,
437	                        发票号码: d.invoiceNo,
438	                        开票日期: d.date,
439	                        单位: d.unit,
440	                        数量: d.qty,
441	                        单价: d.price,
442	                        进项最高单价: jinMax,
443	                        差异: Math.round((jinMax - d.price) * 100) / 100,
444	                        异常说明: `销项单价${d.price} < 进项最高单价${jinMax}`
445	                    });
446	                }
447	            }
448	        }
449	    }
450	    return rows;
451	}
452	
453	// --- Sheet 3: 单价全览 ---
454	function buildPriceOverview(groups, jinData, xiaoData) {
455	    const rows = [];
456	    for (const g of groups) {
457	        const gJinData = jinData.filter(d => d.groupId === g.id);
458	        const gXiaoData = xiaoData.filter(d => d.groupId === g.id);
459	
460	        if (gJinData.length === 0 && gXiaoData.length === 0) continue;
461	
462	        const jinNames = [...g.jinNames].join('; ') || '—';
463	        const xiaoNames = [...g.xiaoNames].join('; ') || '—';
464	
465	        // 进项所有单价(去重排序)
466	        const jinPrices = [...new Set(gJinData.map(d => d.price))].sort((a, b) => a - b);
467	        // 销项所有单价(去重排序)
468	        const xiaoPrices = [...new Set(gXiaoData.map(d => d.price))].sort((a, b) => a - b);
469	
470	        const jinMin = jinPrices.length > 0 ? jinPrices[0] : '—';
471	        const jinMax = jinPrices.length > 0 ? jinPrices[jinPrices.length - 1] : '—';
472	        const xiaoMin = xiaoPrices.length > 0 ? xiaoPrices[0] : '—';
473	        const xiaoMax = xiaoPrices.length > 0 ? xiaoPrices[xiaoPrices.length - 1] : '—';
474	
475	        // 是否有异常
476	        const hasAnomaly = (jinMax !== '—' && xiaoMin !== '—' && parseFloat(jinMax) > parseFloat(xiaoMin));
477	        const jinRows = gJinData.length;
478	        const xiaoRows = gXiaoData.length;
479	
480	        rows.push({
481	            产品组编号: g.id,
482	            进项品类: jinNames,
483	            进项行数: jinRows,
484	            进项单价列表: jinPrices.join(', '),
485	            进项最低单价: jinMin,
486	            进项最高单价: jinMax,
487	            销项品类: xiaoNames,
488	            销项行数: xiaoRows,
489	            销项单价列表: xiaoPrices.join(', '),
490	            销项最低单价: xiaoMin,
491	            销项最高单价: xiaoMax,
